            long old_invalid = (oldLength <= 0) ? 0 : (oldLength * (oldLength + 1)) / 2;
            current_invalid -= old_invalid;

            long leftLength = (long) idx - left - 1;
            long left_invalid = (leftLength <= 0) ? 0 : (leftLength * (leftLength + 1)) / 2;
            current_invalid += left_invalid;

            long rightLength = (long) right - idx - 1;
            long right_invalid = (rightLength <= 0) ? 0 : (rightLength * (rightLength + 1)) / 2;
            current_invalid += right_invalid;

            set.add(idx);

            if (total - current_invalid >= k) {
                return t;
            }
        }
        return -1;
    }
}
